correct:
for (int i = 0; i < 4; i++) {
  int nx = x + dx[i];
  int ny = y + dy[i];
  if (nx < 0 || nx >= n || ny < 0 || ny >= m) continue;
  if (grid[nx][ny] == '#') continue;  // 跳过障碍物！
  if (!vis[nx][ny]) {
    vis[nx][ny] = true;
    queue.push({nx, ny});
  }
}

