wrongCode:
// 错误：用栈代替了队列
stack<int> s;           // 用了 stack！
s.push(start);
vis[start] = true;
while (!s.empty()) {
  auto cur = s.top();
  s.pop();
  for (auto nxt : neighbors(cur)) {
    if (!vis[nxt]) {
      vis[nxt] = true;
      s.push(nxt);      // 后进先出 = DFS
    }
  }
}

correct:
// 正确：使用队列
queue<int> q;           // 用 queue！
q.push(start);
vis[start] = true;
while (!q.empty()) {
  auto cur = q.front();
  q.pop();
  for (auto nxt : neighbors(cur)) {
    if (!vis[nxt]) {
      vis[nxt] = true;
      q.push(nxt);      // 先进先出 = BFS
    }
  }
}

wrongCode:
// 常见错误：忘记初始化距离数组
int d[MAXN][MAXN];  // 没有初始化！
queue.push(start);
vis[start] = true;
while (!q.empty()) {
  auto cur = q.front(); q.pop();
  for (auto nxt : neighbors(cur)) {
    if (!vis[nxt] && grid[nxt] != '#') {
      d[nxt] = d[cur] + 1;  // d[start] 没初始化，d[nxt] 可能是垃圾值
      vis[nxt] = true;
      queue.push(nxt);
    }
  }
}
// d[end] 的值不可靠！

correct:
// 正确的距离初始化
memset(d, -1, sizeof(d));  // -1 表示未到达
d[start] = 0;              // 起点到自己的距离为 0
queue.push(start);
vis[start] = true;
while (!q.empty()) {
  auto cur = q.front(); q.pop();
  for (auto nxt : neighbors(cur)) {
    if (!vis[nxt] && grid[nxt] != '#') {
      d[nxt] = d[cur] + 1;
      vis[nxt] = true;
      queue.push(nxt);
    }
  }
}
// d[end] 就是最短步数
